  int max_num_ff_dist_ = 5;  // maximum number of FF distances between
  float dataflow_factor_ = 2.0;
  float dataflow_weight_ = 1;
  std::vector<std::pair<odb::dbITerm*, std::vector<std::set<odb::dbInst*>>>>
