  }

  parent_->removeChild(&cluster);
  metrics_.addMetrics(cluster.metrics_);
  // modify name
  name_ += "||" + cluster.name_;
  // if current cluster is a leaf cluster
  leaf_macros_.insert(leaf_macros_.end(),
                      cluster.leaf_macros_.begin(),
