void HardMacro::flip(bool flip_horizontal)
{
  if (flip_horizontal) {
    orientation_ = orientation_.flipX();
    pin_y_ = height_ - pin_y_;
  } else {
    orientation_ = orientation_.flipY();
    pin_x_ = width_ - pin_x_;
